public class FindMiddle {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static ListNode middleNode(ListNode head) {
        ListNode slow=head, fast=head;
        while(fast!=null&&fast.next!=null){slow=slow.next;fast=fast.next.next;}
        return slow;
    }
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    public static void main(String[] args){
        System.out.println(middleNode(of(1,2,3,4,5)).val);   // 3
        System.out.println(middleNode(of(1,2,3,4,5,6)).val); // 4
        System.out.println("O(n) time, O(1) space");
    }
}

public class HasCycle {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static boolean hasCycle(ListNode head) {
        ListNode slow=head,fast=head;
        while(fast!=null&&fast.next!=null){
            slow=slow.next; fast=fast.next.next;
            if(slow==fast) return true;
        }
        return false;
    }
    public static void main(String[] args){
        ListNode n=new ListNode(3);n.next=new ListNode(2);n.next.next=new ListNode(0);
        n.next.next.next=new ListNode(-4);n.next.next.next.next=n.next;
        System.out.println(hasCycle(n));          // true
        System.out.println(hasCycle(new ListNode(1))); // false
        System.out.println("O(n) time, O(1) space");
    }
}

public class PalindromeLL {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static boolean isPalindrome(ListNode head) {
        ListNode slow=head,fast=head;
        while(fast!=null&&fast.next!=null){slow=slow.next;fast=fast.next.next;}
        ListNode prev=null,curr=slow;
        while(curr!=null){ListNode n=curr.next;curr.next=prev;prev=curr;curr=n;}
        ListNode l=head,r=prev;
        while(r!=null){if(l.val!=r.val) return false;l=l.next;r=r.next;}
        return true;
    }
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    public static void main(String[] args){
        System.out.println(isPalindrome(of(1,2,2,1))); // true
        System.out.println(isPalindrome(of(1,2)));      // false
        System.out.println(isPalindrome(of(1,2,1)));    // true
        System.out.println("O(n) O(1): find middle + reverse second + compare");
    }
}

public class CycleEntry {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static ListNode detectCycle(ListNode head) {
        ListNode slow=head,fast=head;
        while(fast!=null&&fast.next!=null){
            slow=slow.next;fast=fast.next.next;
            if(slow==fast) break;
        }
        if(fast==null||fast.next==null) return null;
        slow=head;
        while(slow!=fast){slow=slow.next;fast=fast.next;}
        return slow;
    }
    public static void main(String[] args){
        ListNode n=new ListNode(3);n.next=new ListNode(2);n.next.next=new ListNode(0);
        n.next.next.next=new ListNode(-4);n.next.next.next.next=n.next; // cycle to 2
        System.out.println(detectCycle(n).val); // 2
        System.out.println(detectCycle(new ListNode(1))); // null
        System.out.println("Phase 2: reset slow, both speed 1, meet at entry");
    }
}

public class FindDup { public static int findDuplicate(int[] nums){int s=nums[0],f=nums[0];do{s=nums[s];f=nums[nums[f]];}while(s!=f);s=nums[0];while(s!=f){s=nums[s];f=nums[f];}return s;}
    public static void main(String[] a){System.out.println(findDuplicate(new int[]{1,3,4,2,2}));System.out.println(findDuplicate(new int[]{3,1,3,4,2}));System.out.println("O(n) O(1) Floyd on array");}
}

public class ListIntersect { static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static ListNode getIntersectionNode(ListNode a,ListNode b){ListNode p=a,q=b;while(p!=q){p=(p==null?b:p.next);q=(q==null?a:q.next);}return p;}
    public static void main(String[] a){ListNode s=new ListNode(8);s.next=new ListNode(4);ListNode la=new ListNode(4);la.next=new ListNode(1);la.next.next=s;ListNode lb=new ListNode(5);lb.next=s;System.out.println(getIntersectionNode(la,lb).val);System.out.println("O(n+m) O(1)");}
}

public class Happy{static int sq(int n){int s=0;while(n>0){int d=n%10;s+=d*d;n/=10;}return s;}
    public static boolean isHappy(int n){int s=n,f=n;do{s=sq(s);f=sq(sq(f));}while(s!=f);return s==1;}
    public static void main(String[] a){System.out.println(isHappy(19));System.out.println(isHappy(2));System.out.println("Floyd on number sequence");}
}

public class Reorder{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static void reorderList(ListNode head){if(head==null||head.next==null)return;ListNode s=head,f=head;while(f!=null&&f.next!=null){s=s.next;f=f.next.next;}ListNode p=null,c=s.next;s.next=null;while(c!=null){ListNode n=c.next;c.next=p;p=c;c=n;}ListNode l=head,r=p;while(r!=null){ListNode n1=l.next,n2=r.next;l.next=r;r.next=n1;l=n1;r=n2;}}
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    static String str(ListNode h){StringBuilder sb=new StringBuilder();while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("-");h=h.next;}return sb.toString();}
    public static void main(String[] a){ListNode l=of(1,2,3,4,5);reorderList(l);System.out.println(str(l));l=of(1,2,3,4);reorderList(l);System.out.println(str(l));System.out.println("O(n) O(1)");}
}

public class NthEnd{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static int nthFromEnd(ListNode head,int n){ListNode f=head,s=head;for(int i=0;i<n;i++)f=f.next;while(f!=null){f=f.next;s=s.next;}return s.val;}
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    public static void main(String[] a){System.out.println(nthFromEnd(of(1,2,3,4,5),2));System.out.println(nthFromEnd(of(1,2,3),1));System.out.println("O(n) O(1)");}
}

public class CycleLen{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static int cycleLength(ListNode head){ListNode s=head,f=head;while(f!=null&&f.next!=null){s=s.next;f=f.next.next;if(s==f){int len=1;ListNode t=s.next;while(t!=s){t=t.next;len++;}return len;}}return 0;}
    public static void main(String[] a){ListNode n=new ListNode(1);n.next=new ListNode(2);n.next.next=new ListNode(3);n.next.next.next=n;System.out.println(cycleLength(n));System.out.println(cycleLength(new ListNode(1)));System.out.println("O(n) O(1)");}
}

public class FloydsProof{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static ListNode entry(ListNode head){ListNode s=head,f=head;while(f!=null&&f.next!=null){s=s.next;f=f.next.next;if(s==f){s=head;while(s!=f){s=s.next;f=f.next;}return s;}}return null;}
    public static void main(String[] a){for(int e=0;e<4;e++){ListNode[] n=new ListNode[5];for(int i=0;i<5;i++)n[i]=new ListNode(i);for(int i=0;i<4;i++)n[i].next=n[i+1];n[4].next=n[e];ListNode det=entry(n[0]);System.out.println("entry="+e+" detected="+(det!=null?det.val:null)+" ok="+(det==n[e]));}}
}

